function gradientDescent(model, learningRate, iterations):
  for i in range(iterations):
    gradient = computeGradient(model)
    model.weights -= learningRate * gradient
  return model

import numpy as np

def directional_derivative(func, direction):
  return np.dot(func.gradient, direction)

public class GradientVector {
  public static double[] computeGradient(double[] func) {
    double[] gradient = new double[func.length];
    for (int i = 0; i < func.length; i++) {
      gradient[i] = func[i] / func.length;
    }
    return gradient;
  }
}
